use std::sync::atomic::{AtomicBool, Ordering};
use std::thread;
use std::time::Duration;

struct ConfigSignal {
    is_stale: AtomicBool
}

impl Clone for ConfigSignal {
    fn clone(&self) -> Self {
        Self { is_stale: AtomicBool::new(self.is_stale.load(Ordering::SeqCst)) }
    }
}

impl ConfigSignal {
    fn new() -> Self {
        Self { is_stale: AtomicBool::new(true) }
    }

    fn trigger(&self) {
        self.is_stale.store(true, Ordering::Release);
    }

    fn check_status(&self) -> bool {
        self.is_stale.load(Ordering::Acquire)
    }
}

fn main() {
    let signal = ConfigSignal::new();
    let cloned_signal = signal.clone();
    let handle = thread::spawn(move || {
        loop {
            thread::sleep(Duration::from_secs(5));
            println!("Simulating file change detection... Triggering update.");
            cloned_signal.trigger();
        }
    });

    let mut iteration = 0;
    loop {
        thread::sleep(Duration::from_millis(300));
        if signal.check_status() && iteration > 0 {
            println!("Signal detected: Configuration state is stale. Re-rendering UI logic.");
            signal.is_stale.store(false, Ordering::SeqCst);
        } else if iteration == 0 {
             println!("Initial load: Checking status (False). No update needed yet.");
        }
        iteration += 1;
    }
}
